mapper.select:
SELECT id, abnormal_code AS abnormalCode, device_unit_code AS deviceUnitCode, source, abnormal_location AS abnormalLocation, abnormal_type AS abnormalType, safety_output AS safetyOutput, reporter, abnormal_description AS abnormalDescription, report_date AS reportDate, status, handler, handler_name AS handlerName, handler_date AS handlerDate, creator_username AS creatorUsername, creator_name AS creatorName, created_at AS createdAt, updated_at AS updatedAt FROM abnormality_record
AND creator_username = #{creatorUsername}
AND abnormal_code LIKE CONCAT('%', #{abnormalCode}, '%')
AND device_unit_code LIKE CONCAT('%', #{deviceUnitCode}, '%')
AND reporter LIKE CONCAT('%', #{reporter}, '%')
AND report_date = #{reportDate}
AND status = #{status}
AND abnormal_type = #{abnormalType}
ORDER BY id DESC

